-- 1. Electricians x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'web-design',
  'When a homeowner has a tripped fuse board at ten o''clock at night or a landlord needs an EICR completed before a tenancy renewal deadline, they search on their phone and call the first electrician whose website loads quickly, looks professional, and makes it obvious how to get in touch. Electrician websites must be built for urgency. Unlike trades where customers spend weeks comparing options, electrical work often involves immediate need: power failures, faulty wiring discovered during renovations, or compliance deadlines for landlord certificates. Your website needs prominent click-to-call buttons on every page, clear service categorisation separating emergency callouts from planned installations and testing, trust signals displaying your Part P registration, NICEIC or NAPIT certification, and public liability insurance, and a design that loads in under two seconds on a mobile phone over a patchy 4G connection. We build electrician websites that convert panicking homeowners and deadline-pressed landlords into phone calls, while also serving as a professional portfolio for planned work like consumer unit upgrades, EV charger installations, and full domestic rewires.',
  'Over eighty percent of emergency electrical searches happen on mobile phones, often in stressful situations where the homeowner''s power has failed or they have discovered a potentially dangerous wiring issue. A website that loads slowly, buries your phone number, or fails to display your electrical certifications loses these urgent callers to the next search result within seconds. For planned work like rewires and EV charger installations, homeowners check your online presence to verify credentials before committing to a contractor handling safety-critical systems.',
  'We design electrician websites mobile-first with emergency callout prominence. Click-to-call buttons appear on every page with 24/7 availability clearly stated where applicable. Certification badges for NICEIC, NAPIT, and Part P registration are displayed in the header. Service pages separate emergency, testing, and installation work with distinct conversion paths for each.',
  '[{"title": "Emergency callers cannot find your phone number quickly enough", "description": "A homeowner whose fuse board has tripped at nine in the evening is not going to browse your About page. If your phone number requires more than one tap to reach, or your website takes four seconds to load on a mobile connection, they have already called the next electrician on Google. Emergency electrical work is won or lost in the first three seconds of a website visit."}, {"title": "No visible proof of electrical certifications and competence", "description": "Electrical work is safety-critical and legally regulated. Homeowners and landlords need to see your NICEIC or NAPIT registration, Part P compliance status, and public liability insurance before they will trust you with their property''s wiring. Websites that bury or omit these credentials lose work to competitors who display certification badges prominently."}, {"title": "No separation between emergency and planned electrical services", "description": "Emergency callout customers and homeowners planning a full rewire have completely different needs and urgency levels. A website that treats all visitors identically fails to serve either audience effectively. Emergency callers need a phone number immediately. Planned work customers need service detail, pricing guidance, and trust signals. Without distinct pathways, both groups are underserved."}]',
  '[{"title": "Emergency-optimised mobile design with instant call access", "description": "Every page features a prominent sticky click-to-call button with your emergency availability clearly stated. The site loads in under two seconds on mobile connections. Emergency service pages appear first in navigation with clear messaging about response times, service areas, and callout charges. A homeowner with a power failure reaches your phone within two taps of landing on your site."}, {"title": "Certification and trust signal display throughout the site", "description": "NICEIC or NAPIT registration badges, Part P certification status, public liability insurance confirmation, and any additional accreditations are displayed in the site header and reinforced on every service page. For landlord services, specific compliance certifications relevant to EICR testing and HMO electrical requirements are prominently featured."}, {"title": "Service-specific pages with distinct conversion paths", "description": "Separate, optimised pages for emergency callouts, consumer unit upgrades, full and partial rewires, EICR testing, EV charger installations, and commercial electrical work. Each page has its own conversion path: emergency pages prioritise phone calls, testing pages offer online booking, and installation pages feature enquiry forms capturing project details."}]',
  '[{"question": "How important is website speed for an electrician?", "answer": "Critical. Emergency electrical searches happen on mobile phones, often in stressful situations. If your site takes more than two seconds to load, the caller has already tapped the back button and called your competitor. We optimise every element for speed: compressed images, minimal code, fast hosting, and streamlined design that prioritises the phone number above everything else."}, {"question": "Should I display my NICEIC or NAPIT registration on my website?", "answer": "Absolutely, and prominently. These certifications are your primary trust signals. Homeowners may not understand the difference between NICEIC and NAPIT, but they recognise that registered electricians have been assessed and that their work is insured and certified. We display these badges in the header, on every service page, and in the footer so they are visible regardless of where a visitor lands."}, {"question": "Can the website handle both emergency and planned work enquiries?", "answer": "Yes. We build distinct user journeys for each. Emergency visitors see a click-to-call button and your callout availability within one second of landing. Planned work visitors find detailed service pages for rewires, consumer unit upgrades, and EV charger installations with enquiry forms that capture project details. The website adapts to the urgency of each visitor''s need."}, {"question": "How long does an electrician website take to build?", "answer": "Most electrician websites launch within three to four weeks. The streamlined timeline reflects the urgency-focused nature of the design. We prioritise getting your emergency callout pages and click-to-call functionality live quickly, then build out planned service pages, portfolio content, and testimonial sections in the following weeks."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Electricians x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'seo',
  'When someone types emergency electrician near me into Google at eleven o''clock at night, the electricians appearing in the top three map pack results and the first organic positions receive almost every call. There is no second-page browsing for electrical emergencies. The homeowner calls the first credible result and books the callout. For planned services like consumer unit upgrades, EICR certificates, and EV charger installations, visibility in local search results is equally critical because homeowners shortlist electricians from search results and rarely look beyond the first page. The challenge for independent electricians is that national platforms like Checkatrade, Bark, and MyBuilder dominate many electrical search terms, while emergency locksmith-style directories compete aggressively for emergency callout keywords. Our SEO campaigns for electricians target the full spectrum of electrical search terms: emergency callouts with 24/7 urgency signals, compliance-driven services like EICR testing and Part P certification, installation services including rewires and EV chargers, and landlord-focused terms for portfolio electrical testing. Every keyword is mapped to a service-specific, location-targeted page designed to capture the search and convert it into a call or booking.',
  'Emergency electrical searches carry the highest intent of almost any local service query. A homeowner with no power at midnight will call the first electrician they find. If that is not you, you have lost a callout worth one hundred and fifty to three hundred pounds. For planned work, searches like consumer unit upgrade cost or EICR certificate landlord represent homeowners actively seeking quotes. The combined value of these searches in a single Kent town easily exceeds ten thousand pounds per month in potential revenue.',
  'Electrician SEO requires separate strategies for emergency and planned services. Emergency pages are optimised for near me and 24/7 callout terms with schema markup declaring emergency service availability. Planned service pages target specific installation and testing keywords with cost-focused content. Google Business Profile management emphasises rapid review collection after every completed job.',
  '[{"title": "Invisible for emergency electrician searches in your area", "description": "The search term emergency electrician near me is one of the highest-intent local service queries. Homeowners do not scroll to page two during a power failure. If your website does not appear in the top three map pack results or the first organic positions, every late-night callout, every weekend emergency, and every fault-finding job in your area goes to a competitor who invested in search visibility."}, {"title": "Checkatrade and Bark outranking your own website", "description": "Lead generation platforms spend millions ranking for electrician-related keywords, then charge you per lead for enquiries that should flow directly to your business. Without SEO investment, your own website sits beneath multiple platform listings where you are one electrician among dozens, with no portfolio, no certification display, and no differentiation."}, {"title": "No visibility for profitable planned electrical services", "description": "Consumer unit upgrades, full house rewires, EV charger installations, and EICR testing are high-value planned services that homeowners and landlords search for specifically. Most electrician websites have a single services page that fails to rank for any individual service term, missing out on searches from prospects who have already decided they need a specific electrical service and are actively seeking a qualified contractor."}]',
  '[{"title": "Emergency-optimised pages with urgency schema markup", "description": "We build dedicated emergency electrician pages for every town in your service area, each optimised for emergency electrician plus location with schema markup declaring 24/7 availability, emergency service type, and response time commitments. These pages include structured trust signals with NICEIC or NAPIT certification and are designed to convert panicking homeowners into phone calls within seconds."}, {"title": "Service-specific landing pages for planned electrical work", "description": "Individual optimised pages for consumer unit upgrades, full and partial rewires, EICR testing, EV charger installation, outdoor lighting, and commercial electrical services. Each page targets the specific search terms homeowners and landlords use, including cost queries like consumer unit upgrade price and compliance terms like landlord EICR certificate requirements."}, {"title": "Google Business Profile dominance for electrical services", "description": "We optimise your profile with precise electrical service categories, before-and-after photos of consumer unit upgrades and rewires, a structured review generation system that requests feedback after every completed job, and regular Google Posts highlighting emergency availability, seasonal offers, and recently completed projects across your service area."}]',
  '[{"question": "How competitive is SEO for electricians compared to other trades?", "answer": "Electrician SEO is highly competitive because the revenue per emergency callout is significant and planned services like rewires carry high project values. However, most independent electricians have not invested in SEO, so the competition is primarily from national platforms rather than local contractors. This creates strong opportunities for electricians who invest in targeted local SEO."}, {"question": "Can I rank for both emergency and planned electrical services?", "answer": "Yes, and you should. We build separate page clusters for emergency callout terms and planned service terms. Emergency pages target urgency-driven searches with location specificity. Planned service pages target research-driven queries about consumer unit upgrades, rewiring costs, and EV charger installation. Both clusters reinforce your overall domain authority for electrical keywords."}, {"question": "How long before emergency callout SEO delivers results?", "answer": "Emergency electrician searches in specific towns are often less competitive than broader terms. Many electricians see their emergency pages ranking within eight to twelve weeks for targeted town-specific queries. Broader terms like emergency electrician Kent take longer, typically four to six months. We prioritise your highest-value service area towns for early results."}, {"question": "Should I target landlord electrical searches separately?", "answer": "Absolutely. Landlords searching for EICR testing, electrical safety certificates, and HMO electrical compliance have specific needs and budgets. We build landlord-focused content targeting these compliance-driven searches, emphasising your certification qualifications, turnaround times, and portfolio testing capabilities. Landlords with multiple properties represent recurring revenue worth targeting specifically."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
