  faqs = EXCLUDED.faqs;

-- 3. Electricians x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'lead-capture',
  'Electricians receive two fundamentally different types of enquiry: emergency callouts that require an immediate phone response, and planned work like rewires, consumer unit upgrades, and EV charger installations where homeowners research and compare before committing. Most electrician websites serve neither audience well. Emergency callers find a generic contact form instead of a prominent phone number. Planned work prospects find no way to describe their project in detail or get an indicative price without calling during working hours. Purpose-built lead capture for electricians creates distinct pathways for each: instant click-to-call for emergencies with automatic callback scheduling when lines are busy, and structured project enquiry forms for planned work that capture property type, current consumer unit age, number of circuits needed, and specific service requirements. For landlords needing EICR testing across multiple properties, a portfolio submission form captures the number of properties, locations, and required completion dates. Every enquiry type is captured in the format most useful for your quoting process.',
  'An electrician''s time is spent on site, not at a desk answering emails. When a homeowner submits a vague contact form saying I need some electrical work done, you face a ten-minute phone call just to establish what they need. Multiply this by twenty enquiries per week and you lose hours to unqualified conversations. Structured lead capture ensures every planned work enquiry arrives with property details, service requirements, and timeline expectations already captured.',
  'We build separate capture paths for emergency and planned work. Emergency enquiries go straight to click-to-call with a missed-call callback system. Planned work forms capture property age, current consumer unit type, required services, and access details. Landlord EICR forms capture portfolio size, property addresses, and compliance deadlines. Each form feeds into the appropriate follow-up workflow.',
  '[{"title": "Emergency callers hitting a contact form instead of calling", "description": "A homeowner whose power has tripped at nine in the evening does not want to fill in a form and wait for a response. If your website''s primary action is a contact form rather than a prominent phone number, you lose emergency callouts to the competitor whose site makes calling effortless. Every second of friction between landing on your site and hearing your phone ring costs you emergency revenue."}, {"title": "Planned work enquiries arriving without enough detail to quote", "description": "When a homeowner fills in a generic contact form saying they need a rewire, you have no idea whether it is a two-bedroom flat or a five-bedroom house, whether the property has been rewired in the last thirty years, or whether they need the work completed next week or next year. The resulting phone call to gather basic information wastes your time and delays the quoting process."}, {"title": "Landlord EICR enquiries treated identically to domestic requests", "description": "A landlord needing EICR certificates for twelve rental properties represents thousands of pounds in testing revenue and potential ongoing maintenance work. Without a specific enquiry path for portfolio landlords, these high-value commercial clients submit the same generic form as a homeowner needing a socket replaced, and their enquiry receives the same priority."}]',
  '[{"title": "Dual-path lead capture for emergencies and planned work", "description": "Emergency visitors see a sticky click-to-call button with availability status and average response times. If the call is missed, an automated callback scheduling system texts the homeowner with available slots within the next hour. Planned work visitors access structured forms that capture property type, consumer unit age, required services, access details, and preferred timeline, providing everything you need to prepare an informed quote."}, {"title": "Landlord portfolio enquiry forms for EICR testing", "description": "A dedicated landlord enquiry path captures portfolio size, property addresses or postcodes, current certificate expiry dates, and required completion deadlines. This information allows you to quote efficiently for multi-property EICR packages and demonstrate the ability to handle portfolio work at scale, differentiating you from electricians who only handle single domestic properties."}, {"title": "Service-specific quote calculators for common installations", "description": "Interactive calculators for popular services: consumer unit upgrade estimators based on existing board type and required circuits, EV charger installation estimators based on parking distance from the consumer unit, and EICR pricing calculators for landlords based on property size and circuit count. Each calculator captures qualified lead details while providing homeowners with useful indicative pricing."}]',
  '[{"question": "How do you handle emergency and non-emergency enquiries differently?", "answer": "Emergency enquiries are routed to immediate phone contact with a missed-call callback system that texts the homeowner within minutes. Planned work enquiries go through structured forms that capture detailed project information. Landlord EICR enquiries use a portfolio-specific form. Each path is designed for the urgency level and information requirements of that enquiry type."}, {"question": "Can lead capture work for after-hours emergency calls?", "answer": "Yes. If you offer 24/7 callouts, the system routes directly to your phone. If your emergency line has off-hours, the system captures the caller''s details and sends an automated text confirming when you will return their call, along with safety advice for common electrical emergencies. This keeps the lead warm even when you cannot answer immediately."}, {"question": "What information do the planned work forms capture?", "answer": "Forms are tailored to each service. For rewires: property age, number of rooms, current consumer unit type, and any known wiring issues. For consumer unit upgrades: current board make and age, number of circuits, and whether RCD protection is already present. For EV charger installations: vehicle type, parking distance from the consumer unit, and preferred charger brand. This level of detail enables informed quoting without a preliminary phone call."}, {"question": "How does the landlord EICR form work?", "answer": "Landlords enter the number of properties requiring testing, property types and approximate sizes, current certificate expiry dates, and their compliance deadline. The system generates a portfolio summary that allows you to provide a package quote for the entire portfolio. Follow-up sequences include reminders about upcoming certificate expiry dates for properties already tested."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
