-- 4. Electricians x Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'business-automation',
  'Running an electrical contracting business involves managing a constant flow of emergency callouts, planned installations, testing appointments, certificate generation, invoice management, and compliance documentation. Most electricians handle all of this through a combination of a pocket diary, text messages, memory, and end-of-day admin sessions that eat into every evening. A missed EICR renewal reminder costs you a returning landlord client. A forgotten quote follow-up loses a five-thousand-pound rewire. An unchased invoice leaves hundreds outstanding for months because you were too busy on site to send a reminder. Business automation for electricians systematises every repeatable process in your workflow: automatic appointment confirmations and reminders for booked testing and installation work, quote follow-up sequences that chase at appropriate intervals, certificate delivery emails with digital copies of electrical certificates, invoice generation triggered by job completion, and payment chasing sequences that maintain your cash flow without consuming your evenings.',
  'The average electrician spends fifteen to twenty hours per week on administration: quoting, scheduling, certificate paperwork, invoicing, and chasing payments. This is time spent at a desk instead of earning on site. For sole traders and small firms, this admin burden directly limits earning capacity. Every hour spent chasing an invoice or sending appointment reminders is an hour not spent on a billable installation or emergency callout.',
  'Electrical business automation must work around unpredictable schedules where an emergency callout can override a planned diary. Our systems handle dynamic rescheduling when emergencies arise, automatically notifying affected planned work customers and offering alternative slots. Certificate generation integrates with your testing workflows, and compliance reminders ensure landlord EICR renewals never lapse.',
  '[{"title": "Quote follow-ups lost in the chaos of emergency callouts", "description": "You spend an hour at a property assessing a full rewire, prepare a detailed quote, and send it. Then an emergency callout comes in, followed by two more the next day, and the quote follow-up never happens. Three weeks later the homeowner has accepted a competitor''s quote because they followed up and you did not. This pattern repeats weekly, costing thousands in lost planned work."}, {"title": "EICR renewal reminders falling through the cracks", "description": "Landlord EICR certificates expire every five years, and the renewal represents guaranteed repeat revenue. Without a systematic reminder system, certificates expire without your knowledge, the landlord uses a different electrician when they finally notice, and you lose a client worth hundreds of pounds annually across their entire property portfolio."}, {"title": "Certificate paperwork and delivery consuming evenings", "description": "After completing an EICR or installing a new consumer unit, you must generate the appropriate certificate, send copies to the homeowner or landlord, and register the work with your competent person scheme. This paperwork accumulates during busy days and is completed late in the evening, cutting into personal time and often delayed by days or weeks."}]',
  '[{"title": "Automated quote follow-up sequences for planned electrical work", "description": "When you send a quote for a rewire, consumer unit upgrade, or EV charger installation, automated follow-ups trigger at day three, day seven, and day fourteen. Each message references the specific service quoted and the property address. If the homeowner accepts, the system triggers your booking workflow. Quote follow-ups continue working even when emergency callouts dominate your day."}, {"title": "EICR and certificate renewal reminder system", "description": "Every EICR certificate issued is logged with its expiry date. The system automatically contacts landlords six months, three months, and one month before expiry with professional reminders and a direct booking link for the renewal test. This captures repeat revenue automatically and positions you as the proactive, organised electrician their portfolio relies on."}, {"title": "Job completion triggers for certificates and invoicing", "description": "When you mark a job as complete, the system automatically generates and sends the appropriate electrical certificate to the customer, triggers an invoice with your standard terms, and starts a payment chasing sequence if the invoice remains unpaid. For registered work, the system prompts you to submit the notification to your competent person scheme. All paperwork flows from a single job completion action."}]',
  '[{"question": "Can automation handle the unpredictability of emergency callouts?", "answer": "Yes. When you accept an emergency callout that conflicts with a planned appointment, the system automatically notifies the planned work customer with an apology and offers alternative time slots from your available diary. The rescheduled appointment is confirmed automatically, and the customer receives a reminder before the new date. This handles the disruption professionally without you making individual calls."}, {"question": "How does the EICR renewal reminder system work?", "answer": "Every certificate you issue is logged with the property address, landlord contact details, and expiry date. The system sends automated reminders at six months, three months, and one month before expiry. Each reminder includes a direct booking link so the landlord can schedule their renewal test in two clicks. You receive a notification when they book and when a certificate is approaching expiry without response."}, {"question": "Can the system generate electrical certificates automatically?", "answer": "The system generates certificate templates pre-filled with property details, client information, and test results from your standard testing workflow. You complete the technical sections and test readings, and the system handles formatting, delivery to the customer, and prompts for competent person scheme notification. This cuts certificate preparation time significantly while ensuring nothing is missed."}, {"question": "What about invoicing for emergency callouts with different rates?", "answer": "The system applies the correct pricing automatically based on job type. Emergency callouts use your out-of-hours rates. Planned installations use your standard pricing. EICR testing applies your per-circuit or per-property rates. Invoices are generated with the correct amounts, and payment chasing sequences follow your preferred terms for each job type."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
