-- 6. Electricians x Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'social-media-setup',
  'Social media for electricians serves a different purpose than for visual trades like kitchen fitters or landscapers. While dramatic before-and-after transformations are less common, electrical work offers powerful content opportunities that build trust, demonstrate expertise, and generate referrals. Consumer unit upgrade photos showing a dangerous old fuse board replaced with a modern RCD-protected board tell a compelling safety story. EV charger installations showcase your capability with emerging technology. Thermal imaging of overloaded circuits demonstrates your diagnostic expertise. Safety awareness posts about outdated wiring, overloaded extension leads, and the importance of regular testing position you as the knowledgeable, safety-conscious electrician that homeowners trust with their property. We set up your Facebook and Instagram profiles optimised for local electrical contractor visibility, create content templates for the types of posts that generate engagement in the electrical trade, and establish a manageable posting rhythm that maintains your professional presence without requiring hours of content creation after a day on the tools.',
  'Homeowners who find you through Google often check your social media before calling. An active Facebook page with recent job photos, customer reviews, and electrical safety tips validates your credibility. An inactive page or no social presence raises doubts. For electricians, social media also serves as a referral amplifier: when a satisfied customer shares your post about their new consumer unit or EV charger, their friends and neighbours, your ideal local audience, see your work.',
  'We set up electrician social profiles emphasising trust and safety credentials. Profile headers feature your NICEIC or NAPIT certification. Content templates cover consumer unit upgrades with old-versus-new comparisons, EV charger installations, testing and certification work, and electrical safety awareness. Review sharing templates amplify positive Google and Checkatrade feedback across your social audience.',
  '[{"title": "No social presence for homeowners checking your credibility", "description": "When a homeowner finds your website through Google and sees your phone number, their next step is often to search for you on Facebook. An abandoned page with no posts for six months, or no social presence at all, creates doubt about whether you are still active and trustworthy. In a trade where trust is paramount, this social validation gap costs you calls from cautious homeowners."}, {"title": "Electrical work seeming unglamorous compared to visual trades", "description": "Electricians often assume their work is not social media worthy because there are no dramatic kitchen reveals or garden transformations. This misconception means they miss powerful content opportunities: the satisfying before-and-after of a dangerous fuse board replaced with a modern consumer unit, the clean installation of an EV charger, and the diagnostic expertise shown through thermal imaging and testing."}, {"title": "No system for capturing job content during the working day", "description": "You complete a consumer unit upgrade, test the circuits, hand over the certificate, and move to the next job without photographing the work. By the end of a busy day, the last thing you want to do is create social media content. Without a quick capture system, your best trust-building content never reaches your audience."}]',
  '[{"title": "Credential-led profile setup for local visibility", "description": "We configure your Facebook and Instagram profiles with NICEIC or NAPIT certification displayed prominently, business category set to electrician with your service area defined, bio text incorporating key service terms and location, and cover images showcasing your professional appearance and certification. Highlights are organised by service type: emergency callouts, consumer unit upgrades, EV charger installations, and testing services."}, {"title": "Safety-focused content templates for electrical work", "description": "Branded templates for your most effective content types: consumer unit before-and-after posts showing dangerous old boards replaced with modern protection, EV charger installation showcases, electrical safety tips about overloaded sockets and outdated wiring, testing results that demonstrate your thoroughness, and customer review features. Each template requires only a phone photo and two minutes to complete."}, {"title": "Review amplification and referral content system", "description": "When customers leave Google or Checkatrade reviews, branded templates transform them into shareable social posts that reach your local audience. Completed job posts are designed for customer sharing, turning every satisfied client into a referral source. Content about recently completed work in specific towns targets the hyper-local audience most likely to need your services."}]',
  '[{"question": "What kind of social media content works for electricians?", "answer": "Consumer unit upgrade before-and-afters are consistently the highest-engagement electrical content because they tell a visual safety story. EV charger installation posts attract the growing electric vehicle audience. Electrical safety tips generate shares from homeowners who recognise the dangers described. Customer review features build trust. Behind-the-scenes testing work demonstrates your thoroughness and diagnostic skills."}, {"question": "Which platforms should an electrician focus on?", "answer": "Facebook is the primary platform for electricians because it reaches the homeowner demographic, supports local community group engagement, and allows review collection. Instagram works well for visual content like clean installations and testing equipment. We set up both platforms but prioritise Facebook for lead generation and community visibility."}, {"question": "How often should an electrician post on social media?", "answer": "Two to three posts per week maintains visibility without creating unsustainable content demands. With a simple photo capture system for completed jobs, content creation takes minutes per post using branded templates. During busy periods, completed job photos provide abundant content. During quieter weeks, safety tips and seasonal advice fill the calendar."}, {"question": "Can social media generate actual electrical work enquiries?", "answer": "Yes, particularly through referral amplification. When a homeowner shares your post about their new consumer unit upgrade, their local friends see your work. Facebook community group posts about completed work in specific towns generate direct enquiries. Social media also validates your business when homeowners check your online presence before calling your number from a Google search."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
