-- 8. Electricians x Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'electricians',
  'workwear-print',
  'Electricians enter people''s homes every day, often working in bedrooms, kitchens, and living rooms where homeowners are acutely aware of who is in their personal space. The impression your appearance creates at the front door sets the tone for the entire job. A uniformed electrician wearing a branded polo shirt with an embroidered NICEIC logo, presenting a photo ID badge, and carrying tools in a branded bag communicates professionalism and trustworthiness before saying a word. This is even more important when working in rental properties where tenants may not have arranged the visit and are wary of unexpected tradespeople. Branded workwear and professional printed materials including business cards with your certification details, van livery specification sheets for fleet consistency, leave-behind electrical safety checklists, and branded certificate folders create a complete professional identity system. For electricians, physical branding is fundamentally about trust. It reassures homeowners that the person accessing their fuse board, working in their loft space, and connecting circuits in their children''s bedrooms is a qualified, insured, registered professional.',
  'Electrical work involves accessing every room in a home, often when homeowners are out. The trust required is significantly higher than for a tradesperson working in a garage or garden. Unbranded electricians in plain clothing look no different from an unqualified handyman, which creates anxiety for safety-conscious homeowners. Branded workwear with visible certification logos provides instant visual confirmation of your professional status.',
  'We supply workwear selected for indoor electrical work: clean-presenting fabrics suitable for domestic environments, embroidered with your branding and NICEIC or NAPIT certification. Print materials include ID badge systems, branded certificate folders, electrical safety checklists for homeowners, and business cards featuring your registration number and emergency contact details.',
  '[{"title": "Arriving at properties looking indistinguishable from an unqualified tradesperson", "description": "Homeowners cannot tell a fully qualified, NICEIC-registered electrician from an unqualified handyman by appearance alone unless you wear branded workwear with visible certification. When a homeowner opens their door to a stranger who will be working on safety-critical electrical systems, a branded polo shirt with your NICEIC or NAPIT logo creates immediate reassurance that plain clothing simply cannot provide."}, {"title": "No ID system for tenant and elderly customer reassurance", "description": "Tenants in rental properties and elderly homeowners are particularly vulnerable to concerns about admitting tradespeople. Without a professional ID badge system, you rely on verbal explanation to establish your identity. A photo ID badge with your company branding, name, and certification status provides tangible proof that you are who you claim to be."}, {"title": "Electrical certificates presented without professional packaging", "description": "An electrical installation certificate or EICR report is an important safety document that homeowners and landlords must retain. Presenting it as a printed sheet in a plastic wallet diminishes its perceived importance. A branded certificate folder with your company details, care instructions, and contact information for future electrical needs elevates the document and reinforces your professionalism."}]',
  '[{"title": "Professional indoor workwear with certification branding", "description": "Branded polo shirts and softshell jackets in clean, professional colours with embroidered company logo and NICEIC or NAPIT certification badge. Fabrics are selected for indoor domestic environments: comfortable for loft work, presentable in living spaces, and durable enough for daily wear. Optional branded fleece and waterproof jacket for external work including EV charger installations and outdoor lighting projects."}, {"title": "Photo ID badge system with verification capability", "description": "Professional photo ID badges for every electrician in your team, featuring your company branding, the individual''s name and photo, their certification status, and a QR code linking to your company''s online verification page. Presented on a branded lanyard, these badges are shown at every front door and provide tangible reassurance to homeowners, tenants, and vulnerable customers."}, {"title": "Branded certificate folders and electrical safety leave-behinds", "description": "Professional folders for presenting electrical certificates with your branding, contact details, and care information. Electrical safety checklists designed as leave-behind materials after every job, covering topics like fuse board basics, when to call an electrician, and the importance of regular testing. These leave-behinds keep your contact details in the homeowner''s kitchen drawer for future needs."}]',
  '[{"question": "What workwear is appropriate for electricians working inside homes?", "answer": "We supply branded polo shirts and softshell jackets in professional colours that present well in domestic environments. Fabrics are breathable for loft and ceiling void work, easy to keep clean for living space presentation, and durable enough for daily trade use. Embroidered branding and certification logos are positioned for visibility when you present at a homeowner''s door."}, {"question": "How do the ID badges work for a multi-person electrical firm?", "answer": "Each electrician receives a personalised photo ID badge with their name, photo, role, and individual certification status, all within your company branding. Badges are presented on branded lanyards and shown at every property visit. For growing teams, we provide a simple reorder process for new badges as you add staff. Replacement badges for lost or damaged cards are produced quickly."}, {"question": "Can you produce branded certificate folders for EICRs and installation certificates?", "answer": "Yes. We produce professional folders sized for standard electrical certificates with your branding on the front cover, your contact details and emergency number on the inside, and care instructions on the back. These folders are handed to the homeowner or landlord with their certificate, providing a professional presentation that ensures your contact details are retained alongside the safety documentation."}, {"question": "How many sets of workwear does a typical electrician need?", "answer": "We recommend five branded polo shirts per electrician for a full working week rotation, plus two softshell jackets and one waterproof outer layer. This allows daily rotation with washing and ensures you always present professionally. For teams, volume pricing applies and we maintain your design on file for quick reordering as workwear needs replacing."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
